def max_product(arr):
    # We want to find two numbers whose product is the highest.
    # This can be either:
    # - the product of the two largest positive numbers
    # - or the product of the two smallest (most negative) numbers (because negative * negative = positive)
    # So we find the two largest and two smallest numbers and compare their products.

    if len(arr) < 2:
        raise ValueError("Array must have at least two elements")

    # Initialize variables to track two largest and two smallest
    max1 = max2 = float('-inf')
    min1 = min2 = float('inf')

    for num in arr:
        # Update max1 and max2
        if num > max1:
            max2 = max1
            max1 = num
        elif num > max2:
            max2 = num

        # Update min1 and min2
        if num < min1:
            min2 = min1
            min1 = num
        elif num < min2:
            min2 = num

    # Compare products
    if max1 * max2 >= min1 * min2:
        return (max2, max1) if max2 < max1 else (max1, max2)
    else:
        return (min1, min2) if min1 < min2 else (min2, min1)


