def sum_Of_Primes(n):
    if n < 2:
        return 0

    # Sieve of Eratosthenes to find primes up to n
    sieve = [True] * (n+1)
    sieve[0], sieve[1] = False, False

    for i in range(2, int(n**0.5) + 1):
        if sieve[i]:
            for j in range(i*i, n+1, i):
                sieve[j] = False

    return sum(i for i in range(2, n+1) if sieve[i])

