def get_median(arr1, arr2, n):
    # Since both arrays are sorted and of same size,
    # we can use a binary search approach to find the median in O(log n) time.

    # Helper function to find median of a single array
    def median(arr):
        length = len(arr)
        if length % 2 == 0:
            return (arr[length//2 - 1] + arr[length//2]) / 2
        else:
            return arr[length//2]

    # Base cases
    if n == 1:
        return (arr1[0] + arr2[0]) / 2
    if n == 2:
        return (max(arr1[0], arr2[0]) + min(arr1[1], arr2[1])) / 2

    m1 = median(arr1)
    m2 = median(arr2)

    # If medians are equal, return either
    if m1 == m2:
        return m1

    # If m1 < m2, median must be in arr1[m1_end ...] and arr2[... m2_start]
    if m1 < m2:
        if n % 2 == 0:
            return get_median(arr1[n//2 - 1:], arr2[:n//2 + 1], n - n//2 + 1)
        else:
            return get_median(arr1[n//2:], arr2[:n//2 + 1], n - n//2)
    else:
        # m1 > m2
        if n % 2 == 0:
            return get_median(arr1[:n//2 + 1], arr2[n//2 - 1:], n - n//2 + 1)
        else:
            return get_median(arr1[:n//2 + 1], arr2[n//2:], n - n//2)

