def smallest_missing(arr, start, end):
    # If start is greater than end, smallest missing is end+1
    if start > end:
        return end + 1

    # If the first element is not equal to start, then start is missing
    if arr[start] != start:
        return start

    mid = (start + end) // 2

    # If element at mid is equal to mid, missing element must be in right half
    if arr[mid] == mid:
        return smallest_missing(arr, mid + 1, end)
    else:
        # Otherwise missing element is in left half
        return smallest_missing(arr, start, mid)

