def check_expression(expr: str) -> bool:
    stack = []
    pairs = {'}': '{', ']': '[', ')': '('}
    for char in expr:
        if char in '{[(':
            stack.append(char)
        elif char in '}])':
            if not stack or stack.pop() != pairs[char]:
                return False
    return not stack

