def find_Max(arr, low, high):
    # If the array is not rotated (sorted in ascending order)
    if arr[low] <= arr[high]:
        return arr[high]

    while low <= high:
        mid = (low + high) // 2

        # Check if mid is the maximum element
        if mid < high and arr[mid] > arr[mid + 1]:
            return arr[mid]
        # Check if mid-1 is the maximum element
        if mid > low and arr[mid] < arr[mid - 1]:
            return arr[mid - 1]

        # Decide which half to choose for next step
        if arr[mid] >= arr[low]:
            low = mid + 1
        else:
            high = mid - 1

# Assertions to test the function
